(window.webpackJsonp=window.webpackJsonp||[]).push([[612],{907:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">limit</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minMoves = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums, limit</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> len=nums.length\\n    <span class=\\"hljs-keyword\\">let</span> delta=<span class=\\"hljs-built_in\\">Array</span>(<span class=\\"hljs-number\\">2</span>*limit+<span class=\\"hljs-number\\">2</span>).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i &lt; len / <span class=\\"hljs-number\\">2</span>; ++i){\\n        <span class=\\"hljs-keyword\\">let</span> lo=<span class=\\"hljs-number\\">1</span>+<span class=\\"hljs-built_in\\">Math</span>.min(nums[i],nums[len<span class=\\"hljs-number\\">-1</span>-i])\\n        <span class=\\"hljs-keyword\\">let</span> hi=limit+<span class=\\"hljs-built_in\\">Math</span>.max(nums[i],nums[len<span class=\\"hljs-number\\">-1</span>-i])\\n        <span class=\\"hljs-keyword\\">let</span> sum=nums[i]+nums[len<span class=\\"hljs-number\\">-1</span>-i]\\n        delta[lo]--\\n        delta[sum]--\\n        delta[sum+<span class=\\"hljs-number\\">1</span>]++\\n        delta[hi+<span class=\\"hljs-number\\">1</span>]++\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> now = len;\\n    <span class=\\"hljs-keyword\\">let</span> ans = len;\\n    <span class=\\"hljs-keyword\\">for</span> (<span class=\\"hljs-keyword\\">let</span> i = <span class=\\"hljs-number\\">2</span>; i &lt;= limit * <span class=\\"hljs-number\\">2</span>; ++i) {\\n        now += delta[i];\\n        ans = <span class=\\"hljs-built_in\\">Math</span>.min(ans, now);\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> ans;\\n};\\n</code></pre>\\n"],"titleSlug":"minimum-moves-to-make-array-complementary","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u957f\u5ea6\u4e3a<strong> \u5076\u6570</strong> <code>n</code> \u7684\u6574\u6570\u6570\u7ec4 <code>nums</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>limit</code> \u3002\u6bcf\u4e00\u6b21\u64cd\u4f5c\uff0c\u4f60\u53ef\u4ee5\u5c06 <code>nums</code> \u4e2d\u7684\u4efb\u4f55\u6574\u6570\u66ff\u6362\u4e3a\xa0<code>1</code>\xa0\u5230\xa0<code>limit</code> \u4e4b\u95f4\u7684\u53e6\u4e00\u4e2a\u6574\u6570\u3002</p>\\n\\n<p>\u5982\u679c\u5bf9\u4e8e\u6240\u6709\u4e0b\u6807 <code>i</code>\uff08<strong>\u4e0b\u6807\u4ece </strong><code>0</code><strong> \u5f00\u59cb</strong>\uff09\uff0c<code>nums[i] + nums[n - 1 - i]</code>\xa0\u90fd\u7b49\u4e8e\u540c\u4e00\u4e2a\u6570\uff0c\u5219\u6570\u7ec4 <code>nums</code> \u662f <strong>\u4e92\u8865\u7684</strong> \u3002\u4f8b\u5982\uff0c\u6570\u7ec4 <code>[1,2,3,4]</code> \u662f\u4e92\u8865\u7684\uff0c\u56e0\u4e3a\u5bf9\u4e8e\u6240\u6709\u4e0b\u6807\xa0<code>i</code> \uff0c<code>nums[i] + nums[n - 1 - i] = 5</code> \u3002</p>\\n\\n<p>\u8fd4\u56de\u4f7f\u6570\u7ec4 <strong>\u4e92\u8865</strong> \u7684 <strong>\u6700\u5c11</strong>\xa0\u64cd\u4f5c\u6b21\u6570\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [1,2,4,3], limit = 4\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u7ecf\u8fc7 1 \u6b21\u64cd\u4f5c\uff0c\u4f60\u53ef\u4ee5\u5c06\u6570\u7ec4 nums \u53d8\u6210 [1,2,<strong>2</strong>,3]\uff08\u52a0\u7c97\u5143\u7d20\u662f\u53d8\u66f4\u7684\u6570\u5b57\uff09\uff1a\\nnums[0] + nums[3] = 1 + 3 = 4.\\nnums[1] + nums[2] = 2 + 2 = 4.\\nnums[2] + nums[1] = 2 + 2 = 4.\\nnums[3] + nums[0] = 3 + 1 = 4.\\n\u5bf9\u4e8e\u6bcf\u4e2a i \uff0cnums[i] + nums[n-1-i] = 4 \uff0c\u6240\u4ee5 nums \u662f\u4e92\u8865\u7684\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [1,2,2,1], limit = 2\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u7ecf\u8fc7 2 \u6b21\u64cd\u4f5c\uff0c\u4f60\u53ef\u4ee5\u5c06\u6570\u7ec4 nums \u53d8\u6210 [<strong>2</strong>,2,2,<strong>2</strong>] \u3002\u4f60\u4e0d\u80fd\u5c06\u4efb\u4f55\u6570\u5b57\u53d8\u66f4\u4e3a 3 \uff0c\u56e0\u4e3a 3 > limit \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [1,2,1,2], limit = 2\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>nums \u5df2\u7ecf\u662f\u4e92\u8865\u7684\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == nums.length</code></li>\\n\\t<li><code>2 <= n\xa0<=\xa010<sup>5</sup></code></li>\\n\\t<li><code>1 <= nums[i]\xa0<= limit <=\xa010<sup>5</sup></code></li>\\n\\t<li><code>n</code> \u662f\u5076\u6570\u3002</li>\\n</ul>\\n","title":"1674. \u4f7f\u6570\u7ec4\u4e92\u8865\u7684\u6700\u5c11\u64cd\u4f5c\u6b21\u6570","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1674"}')}}]);